import { Client } from '@vex_dev/sdk';

const vex = new Client({
  projectId: 'your-project-id',
  secret: process.env.VEX_SECRET
});

// n8n AI Agent Tool Definition
const tools = [
  {
    name: 'verified_api_call',
    description: 'Make verified API call through Vex',
    parameters: {
      type: 'object',
      properties: {
        url: { type: 'string' },
        method: { type: 'string', enum: ['GET', 'POST'] },
        body: { type: 'object' }
      }
    },
    execute: async ({ url, method, body }) => {
      const result = await vex.verify({
        action: 'api_call',
        input: { url, method, body },
        policies: ['action_correctness', 'permission_check']
      });
      return result.output;
    }
  }
];

// n8n Webhook Node Configuration
const webhookUrl = 'https://api.vex.dev/v1/verify/your-project-id';

const verifyPayload = {
  input: $json, // AI Agent output
  context: {
    workflowId: $workflow.id,
    executionId: $execution.id,
    recursionDepth: $vars.recursionDepth || 0
  },
  policies: [
    'prevent_recursion',
    'validate_schema',
    'check_permissions',
    'ensure_idempotency'
  ]
};

// Set headers
const headers = {
  'Authorization': `Bearer ${$env.VEX_SECRET}`,
  'Content-Type': 'application/json'
};

// n8n IF Node Expression (after Vex webhook)
const vexResult = $json;

if (vexResult.status === 'approved' && !vexResult.risks.length) {
  // Proceed to action nodes
  return 'approved_path';
} else if (vexResult.risks.includes('recursion')) {
  // Rollback and notify
  await $executeWorkflow('rollback_workflow', {
    originalExecutionId: $execution.id
  });
  return 'rollback_path';
} else {
  // Human approval
  return 'human_review_path';
}

import { z } from 'zod';

const memorySchema = z.object({
  messages: z.array(z.object({
    timestamp: z.number(),
    role: z.enum(['user', 'assistant']),
    content: z.string()
  })),
  maxAgeMinutes: z.number().default(60)
});

const verifyMemory = async (memory: any) => {
  const parsed = memorySchema.parse(memory);
  const now = Date.now() / 1000;
  const staleMessages = parsed.messages.filter(
    m => (now - m.timestamp / 1000) > parsed.maxAgeMinutes * 60
  );

  if (staleMessages.length > 3) {
    throw new Error('Stale memory detected');
  }

  return vex.verify({
    action: 'use_memory',
    input: { memory: parsed, staleCount: staleMessages.length },
    policies: ['context_freshness']
  });
};

