// Vex Dashboard Policy Configuration (TypeScript SDK)
await vex.policies.create({
  name: 'n8n-workflow-safety',
  rules: [
    {
      name: 'prevent_recursion',
      type: 'guardrail',
      condition: 'context.recursionDepth > 5',
      action: 'block',
      message: 'Recursion depth exceeded'
    },
    {
      name: 'validate_api_params',
      type: 'schema',
      schema: {
        url: { type: 'string', pattern: '^https?://' },
        method: { enum: ['GET', 'POST', 'PUT', 'DELETE'] },
        headers: { redact: ['Authorization'] }
      }
    }
  ]
});

// n8n Function Node - Generate Idempotency Key
const crypto = require('crypto');

const idempotencyKey = crypto
  .createHash('sha256')
  .update(JSON.stringify({
    workflowId: $workflow.id,
    executionId: $execution.id,
    stepHash: $json.input_hash || $json.toString()
  }))
  .digest('hex');

return {
  ...$json,
  idempotency_key: idempotencyKey,
  verification_id: `n8n-${idempotencyKey.slice(0, 8)}`
};

// Vex Policy with Human Review
const humanReviewPolicy = {
  name: 'medium_risk_human_review',
  riskProfile: 'medium',
  rules: [
    {
      condition: 'risks.length > 2 || risks.includes("credential")',
      action: 'human_review',
      channels: ['slack:#ai-ops', 'email:approvers@company.com'],
      message: `Review required: ${{input.action}}\nRisks: ${{risks.join(', ')}}`
    }
  ]
};

// n8n Wait Node after Vex
const waitForApproval = {
  resume: 'webhook',
  webhookUrl: `${$env.N8N_BASE_URL}/webhook/approval-${$execution.id}`,
  timeout: 3600 // 1 hour
};
